INSERT INTO scenario_groups (id, slug, category) VALUES
  ('00000000-0000-0000-0000-000000000019', 'japan-specific1', 'culture')
INSERT INTO scenarios (id, group_id, language_id, title, description, level, type, icon, sort_order) VALUES
  (
INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation) VALUES
  ('00000000-0000-0000-0009-000000000001', 'en', 1, 'user', 'The weather''s been so humid lately, hasn''t it?', 'Dạo này thời tiết ẩm ướt quá nhỉ?'),
  ('00000000-0000-0000-0009-000000000001', 'en', 2, 'partner', 'Really! I feel like summer came early this year.', 'Đúng vậy! Tôi cảm giác mùa hè đến sớm hơn năm nay.'),
  ('00000000-0000-0000-0009-000000000001', 'en', 3, 'user', 'I know — and the rainy season hasn''t even started yet.', 'Đúng vậy — và mùa mưa thậm chí chưa bắt đầu.'),
  ('00000000-0000-0000-0009-000000000001', 'en', 4, 'partner', 'Oh, I know. The rainy season here is tough. Do you find it hard to deal with?', 'Tôi biết. Mùa mưa ở đây rất khắc nghiệt. Bạn thấy khó chịu không?'),
  ('00000000-0000-0000-0009-000000000001', 'en', 5, 'user', 'A little — especially the mould. I have to run the dehumidifier every day.', 'Một chút — đặc biệt là nấm mốc. Tôi phải chạy máy hút ẩm mỗi ngày.'),
  ('00000000-0000-0000-0009-000000000001', 'en', 6, 'partner', 'Same here. But the hydrangeas are beautiful in the rainy season, at least.', 'Tôi cũng vậy. Nhưng hoa cẩm tú cầu rất đẹp trong mùa mưa, ít nhất là vậy.'),
  ('00000000-0000-0000-0009-000000000001', 'en', 7, 'user', 'That''s true — every season has something. What''s your favourite season in Japan?', 'Đúng vậy — mỗi mùa đều có điều gì đó. Mùa yêu thích của bạn ở Nhật là gì?'),
  ('00000000-0000-0000-0009-000000000001', 'en', 8, 'partner', 'Autumn, for sure. The leaves are gorgeous and the weather is perfect for walking.', 'Chắc chắn là mùa thu. Lá rất đẹp và thời tiết hoàn hảo để đi bộ.'),
  ('00000000-0000-0000-0009-000000000001', 'en', 9, 'user', 'I think autumn is wonderful here too. The light is different somehow.', 'Tôi cũng nghĩ mùa thu ở đây rất tuyệt. Ánh sáng cũng có gì đó khác.'),
  ('00000000-0000-0000-0009-000000000001', 'en', 10, 'partner', 'Exactly. Well, let''s hope the summer isn''t too brutal this year.', 'Đúng vậy. Vậy thì hy vọng mùa hè năm nay không quá khắc nghiệt.'),
  ('00000000-0000-0000-0009-000000000001', 'en', 11, 'user', 'I hope so! Apparently it may be hotter than average this year.', 'Tôi cũng hy vọng! Nghe nói năm nay có thể nóng hơn trung bình.'),
  ('00000000-0000-0000-0009-000000000001', 'en', 12, 'partner', 'I heard that too. Better stock up on those cooling towels now!', 'Tôi cũng nghe vậy. Tốt hơn là mua nhiều khăn lạnh từ bây giờ đi!');
INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation, furigana, romaji) VALUES
  ('00000000-0000-0000-0009-000000000002', 'ja', 1, 'user', '最近、蒸し暑い日が続きますね。', 'Dạo này thời tiết oi bức liên tục nhỉ.', 'さいきん、むしあついひがつづきますね。', 'Saikin, mushiatsui hi ga tsuzukimasu ne.'),
  ('00000000-0000-0000-0009-000000000002', 'ja', 2, 'partner', 'そうですね！今年は夏が早く来た気がしますよ。', 'Đúng vậy! Tôi cảm giác mùa hè đến sớm năm nay.', 'そうですね！ことしはなつがはやくきたきがしますよ。', 'Sō desu ne! Kotoshi wa natsu ga hayaku kita ki ga shimasu yo.'),
  ('00000000-0000-0000-0009-000000000002', 'ja', 3, 'user', '本当に。梅雨もまだ始まっていないのに。', 'Thật vậy. Mùa mưa thậm chí chưa bắt đầu.', 'ほんとうに。つゆもまだはじまっていないのに。', 'Hontō ni. Tsuyu mo mada hajimatte inai no ni.'),
  ('00000000-0000-0000-0009-000000000002', 'ja', 4, 'partner', 'そうなんですよ。梅雨はきついですね。梅雨は苦手ですか？', 'Đúng vậy. Mùa mưa rất khó chịu. Bạn không thích mùa mưa à?', 'そうなんですよ。つゆはきついですね。つゆはにがてですか？', 'Sō nan desu yo. Tsuyu wa kitsui desu ne. Tsuyu wa nigate desu ka?'),
  ('00000000-0000-0000-0009-000000000002', 'ja', 5, 'user', '少し苦手です。特にカビが…。毎日除湿機を使っています。', 'Hơi không thích. Đặc biệt là nấm mốc... Tôi dùng máy hút ẩm mỗi ngày.', 'すこしにがてです。とくにカビが…。まいにちじょしつきをつかっています。', 'Sukoshi nigate desu. Toku ni kabi ga... Mainichi joshitsuki wo tsukatte imasu.'),
  ('00000000-0000-0000-0009-000000000002', 'ja', 6, 'partner', '私もそうです。でも、梅雨のアジサイはきれいですよね。', 'Tôi cũng vậy. Nhưng hoa cẩm tú cầu mùa mưa rất đẹp nhỉ.', 'わたしもそうです。でも、つゆのアジサイはきれいですよね。', 'Watashi mo sō desu. Demo, tsuyu no ajisai wa kirei desu yo ne.'),
  ('00000000-0000-0000-0009-000000000002', 'ja', 7, 'user', '確かに。どの季節にも良いものがありますね。日本で一番好きな季節はいつですか？', 'Đúng vậy. Mỗi mùa đều có điều gì đó. Mùa yêu thích của bạn ở Nhật là gì?', 'たしかに。どのきせつにもよいものがありますね。にほんでいちばんすきなきせつはいつですか？', 'Tashika ni. Dono kisetsu ni mo yoi mono ga arimasu ne. Nihon de ichiban suki na kisetsu wa itsu desu ka?'),
  ('00000000-0000-0000-0009-000000000002', 'ja', 8, 'partner', 'やっぱり秋ですね。紅葉がきれいで、散歩するのにもちょうどいい気候で。', 'Vẫn là mùa thu. Lá đỏ đẹp và thời tiết hoàn hảo để đi bộ.', 'やっぱりあきですね。こうようがきれいで、さんぽするのにもちょうどいいきこうで。', 'Yappari aki desu ne. Kōyō ga kirei de, sanpo suru no ni mo chōdo ii kikō de.'),
  ('00000000-0000-0000-0009-000000000002', 'ja', 9, 'user', '私も日本の秋が好きです。光の感じがどことなく違いますよね。', 'Tôi cũng thích mùa thu Nhật Bản. Ánh sáng có gì đó khác biệt nhỉ.', 'わたしもにほんのあきがすきです。ひかりのかんじがどことなくちがいますよね。', 'Watashi mo Nihon no aki ga suki desu. Hikari no kanji ga doko to naku chigaimasu yo ne.'),
  ('00000000-0000-0000-0009-000000000002', 'ja', 10, 'partner', 'そうなんですよ。今年の夏はそんなに厳しくないといいですね。', 'Đúng vậy. Hy vọng mùa hè năm nay không quá khắc nghiệt.', 'そうなんですよ。ことしのなつはそんなにきびしくないといいですね。', 'Sō nan desu yo. Kotoshi no natsu wa son''na ni kibishikunai to ii desu ne.'),
  ('00000000-0000-0000-0009-000000000002', 'ja', 11, 'user', 'ですね！今年は平均より暑くなるかもしれないって聞きました。', 'Đúng vậy! Tôi nghe nói năm nay có thể nóng hơn trung bình.', 'ですね！ことしはへいきんよりあつくなるかもしれないってききました。', 'Desu ne! Kotoshi wa heikin yori atsuku naru kamo shirenai tte kikimashita.'),
  ('00000000-0000-0000-0009-000000000002', 'ja', 12, 'partner', '私も聞きました。今のうちに冷感タオルを買いだめした方がいいかもしれませんね！', 'Tôi cũng nghe vậy. Có lẽ nên mua trữ khăn lạnh từ bây giờ!', 'わたしもききました。いまのうちにれいかんタオルをかいだめしたほうがいいかもしれませんね！', 'Watashi mo kikimashita. Ima no uchi ni reikan taoru wo kaidame shita hō ga ii kamo shiremasen ne!');
INSERT INTO scenario_groups (id, slug, category) VALUES
  ('00000000-0000-0000-0000-000000000020', 'japan-specific2', 'culture')
INSERT INTO scenarios (id, group_id, language_id, title, description, level, type, icon, sort_order) VALUES
  (
INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation) VALUES
  ('00000000-0000-0000-0009-000000000003', 'en', 1, 'partner', 'Could I get three apples, please?', 'Tôi có thể lấy ba quả táo không?'),
  ('00000000-0000-0000-0009-000000000003', 'en', 2, 'user', 'Of course. Three apples — in Japanese that''s みっつ or りんご三個.', 'Tất nhiên. Ba quả táo — trong tiếng Nhật là みっつ hoặc りんご三個.'),
  ('00000000-0000-0000-0009-000000000003', 'en', 3, 'partner', 'And if I wanted three pencils?', 'Còn nếu tôi muốn ba cái bút chì?'),
  ('00000000-0000-0000-0009-000000000003', 'en', 4, 'user', 'Pencils are long, so you use the counter 本 — えんぴつ三本. 本 is for long, thin objects like bottles and umbrellas too.', 'Bút chì là đồ dài, nên dùng đơn vị đếm 本 — えんぴつ三本. 本 dùng cho đồ dài, mỏng như chai và ô cũng vậy.'),
  ('00000000-0000-0000-0009-000000000003', 'en', 5, 'partner', 'What about paper? Or flat things like shirts?', 'Còn giấy thì sao? Hay đồ phẳng như áo sơ mi?'),
  ('00000000-0000-0000-0009-000000000003', 'en', 6, 'user', 'Flat things use 枚 — かみ一枚 is one sheet of paper, シャツ二枚 is two shirts.', 'Đồ phẳng dùng 枚 — かみ一枚 là một tờ giấy, シャツ二枚 là hai cái áo sơ mi.'),
  ('00000000-0000-0000-0009-000000000003', 'en', 7, 'partner', 'This is tricky! How about floors in a building?', 'Khó quá! Còn tầng trong tòa nhà thì sao?'),
  ('00000000-0000-0000-0009-000000000003', 'en', 8, 'user', 'Floors use 階 — いっかい is the first floor, にかい is second, さんがい is third. Watch out — 一階 in Japan is the ground floor, not the floor above.', 'Tầng dùng 階 — いっかい là tầng một, にかい là tầng hai, さんがい là tầng ba. Lưu ý — 一階 ở Nhật là tầng trệt, không phải tầng trên.'),
  ('00000000-0000-0000-0009-000000000003', 'en', 9, 'partner', 'And dates — how do you say the fourteenth?', 'Còn ngày tháng — bạn nói ngày 14 thế nào?'),
  ('00000000-0000-0000-0009-000000000003', 'en', 10, 'user', 'じゅうよっか. Dates one to ten have special readings — ついたち, ふつか, みっか — then from eleven it''s more regular, but 14 is じゅうよっか and 20 is はつか.', 'じゅうよっか. Ngày 1 đến 10 có cách đọc đặc biệt — ついたち, ふつか, みっか — rồi từ 11 thì đều đặn hơn, nhưng ngày 14 là じゅうよっか và ngày 20 là はつか.'),
  ('00000000-0000-0000-0009-000000000003', 'en', 11, 'partner', 'And money — how do I say eight hundred and fifty yen?', 'Còn tiền — tôi nói tám trăm năm mươi yên thế nào?'),
  ('00000000-0000-0000-0009-000000000003', 'en', 12, 'user', 'はっぴゃくごじゅうえん — eight hundred is はっぴゃく, fifty is ごじゅう, and yen is えん. Good news: no cents, so money in Japan is always whole numbers!', 'はっぴゃくごじゅうえん — tám trăm là はっぴゃく, năm mươi là ごじゅう, và yên là えん. Tin vui: không có xu, nên tiền ở Nhật luôn là số nguyên!');
INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation, furigana, romaji) VALUES
  ('00000000-0000-0000-0009-000000000004', 'ja', 1, 'partner', 'りんごを3つください。', 'Tôi muốn 3 quả táo.', 'りんごをみっつください。', 'Ringo wo mittsu kudasai.'),
  ('00000000-0000-0000-0009-000000000004', 'ja', 2, 'user', 'はい。丸いものを数えるときは「個」を使いますね。りんご3個です。', 'Vâng. Đếm đồ tròn thì dùng 「個」. Là りんご3個.', 'はい。まるいものをかぞえるときは「こ」をつかいますね。りんごさんこです。', 'Hai. Marui mono wo kazoeru toki wa ''ko'' wo tsukaimasu ne. Ringo san-ko desu.'),
  ('00000000-0000-0000-0009-000000000004', 'ja', 3, 'partner', 'えんぴつを3本欲しい場合はどう言いますか？', 'Nếu muốn 3 cái bút chì thì nói thế nào?', 'えんぴつをさんぼんほしいばあいはどういいますか？', 'Enpitsu wo san-bon hoshii baai wa dō iimasu ka?'),
  ('00000000-0000-0000-0009-000000000004', 'ja', 4, 'user', '細長いものには「本」を使います。えんぴつ3本ですね。瓶や傘も「本」で数えますよ。', 'Đồ dài mỏng thì dùng 「本」. Là えんぴつ3本. Chai và ô cũng đếm bằng 「本」nhé.', 'ほそながいものには「ほん」をつかいます。えんぴつさんぼんですね。びんやかさも「ほん」でかぞえますよ。', 'Hosonagai mono ni wa ''hon'' wo tsukaimasu. Enpitsu san-bon desu ne. Bin ya kasa mo ''hon'' de kazoemasu yo.'),
  ('00000000-0000-0000-0009-000000000004', 'ja', 5, 'partner', '紙やシャツのような平たいものはどうですか？', 'Còn đồ phẳng như giấy hay áo sơ mi thì sao?', 'かみやシャツのようなひらたいものはどうですか？', 'Kami ya shatsu no yō na hiratai mono wa dō desu ka?'),
  ('00000000-0000-0000-0009-000000000004', 'ja', 6, 'user', '平たいものには「枚」を使います。かみ1枚、シャツ2枚という感じです。', 'Đồ phẳng thì dùng 「枚」. Ví dụ: かみ1枚, シャツ2枚.', 'ひらたいものには「まい」をつかいます。かみいちまい、シャツにまいというかんじです。', 'Hiratai mono ni wa ''mai'' wo tsukaimasu. Kami ichi-mai, shatsu ni-mai to iu kanji desu.'),
  ('00000000-0000-0000-0009-000000000004', 'ja', 7, 'partner', '難しいですね！建物の階はどうやって言いますか？', 'Khó quá! Tầng của tòa nhà thì nói thế nào?', 'むずかしいですね！たてもののかいはどうやっていいますか？', 'Muzukashii desu ne! Tatemono no kai wa dō yatte iimasu ka?'),
  ('00000000-0000-0000-0009-000000000004', 'ja', 8, 'user', '階には「階」を使います。1階（いっかい）、2階（にかい）、3階（さんがい）です。日本では1階が地上階（グラウンドフロア）ですよ。', 'Tầng thì dùng 「階」. 1階（いっかい）, 2階（にかい）, 3階（さんがい）. Ở Nhật 1階 là tầng trệt nhé.', 'かいには「かい」をつかいます。いっかい、にかい、さんがいです。にほんではいっかいがちじょうかいです。', 'Kai ni wa ''kai'' wo tsukaimasu. Ikkai, ni-kai, san-gai desu. Nihon de wa ikkai ga chijō-kai desu yo.'),
  ('00000000-0000-0000-0009-000000000004', 'ja', 9, 'partner', '日付はどうですか？14日はどう言いますか？', 'Ngày tháng thì sao? Ngày 14 nói thế nào?', 'ひづけはどうですか？じゅうよっかはどういいますか？', 'Hizuke wa dō desu ka? Jū-yokka wa dō iimasu ka?'),
  ('00000000-0000-0000-0009-000000000004', 'ja', 10, 'user', '14日は「じゅうよっか」です。1日から10日には特別な読み方があります。ついたち・ふつか・みっかなど。20日（はつか）も特別ですよ。', 'Ngày 14 là 「じゅうよっか」. Ngày 1–10 có cách đọc đặc biệt: ついたち・ふつか・みっか v.v. Ngày 20 (はつか) cũng đặc biệt.', 'じゅうよっかは「じゅうよっか」です。いちにちからとおかにはとくべつなよみかたがあります。ついたち・ふつか・みっかなど。はつかもとくべつですよ。', 'Jū-yokka wa ''jū-yokka'' desu. Tsuitachi kara tōka ni wa tokubetsu na yomikata ga arimasu. Tsuitachi, futsuka, mikka nado. Hatsuka mo tokubetsu desu yo.'),
  ('00000000-0000-0000-0009-000000000004', 'ja', 11, 'partner', 'お金はどうですか？850円はどう言いますか？', 'Còn tiền thì sao? 850 yên nói thế nào?', 'おかねはどうですか？はっぴゃくごじゅうえんはどういいますか？', 'O-kane wa dō desu ka? Happyaku gojū en wa dō iimasu ka?'),
  ('00000000-0000-0000-0009-000000000004', 'ja', 12, 'user', '850円は「はっぴゃくごじゅうえん」です。日本では小銭（セント）がないので、お金は常に整数です。計算しやすいですよ！', '850 yên là 「はっぴゃくごじゅうえん」. Ở Nhật không có xu nên tiền luôn là số nguyên. Dễ tính lắm!', 'はっぴゃくごじゅうえんは「はっぴゃくごじゅうえん」です。にほんではこぜにがないので、おかねはつねにせいすうです。けいさんしやすいですよ！', 'Happyaku gojū en wa ''happyaku gojū en'' desu. Nihon de wa kozeni ga nai node, o-kane wa tsuneni seisū desu. Keisan shiyasui desu yo!');
INSERT INTO scenario_groups (id, slug, category) VALUES
  ('00000000-0000-0000-0000-000000000021', 'japan-specific3', 'culture')
INSERT INTO scenarios (id, group_id, language_id, title, description, level, type, icon, sort_order) VALUES
  (
INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation) VALUES
  ('00000000-0000-0000-0009-000000000005', 'en', 1, 'partner', 'いらっしゃいませ！', 'Chào mừng quý khách!'),
  ('00000000-0000-0000-0009-000000000005', 'en', 2, 'user', 'Hi. Could you heat this up for me, please? [holding a bento box]', 'Xin chào. Bạn có thể hâm nóng cái này cho tôi không? [cầm hộp cơm bento]'),
  ('00000000-0000-0000-0009-000000000005', 'en', 3, 'partner', 'Of course. Will that be all?', 'Tất nhiên. Bạn còn muốn thêm gì không?'),
  ('00000000-0000-0000-0009-000000000005', 'en', 4, 'user', 'I also have this coffee and this sandwich.', 'Tôi cũng có cái cà phê và cái bánh mì sandwich này.'),
  ('00000000-0000-0000-0009-000000000005', 'en', 5, 'partner', 'Do you have a point card?', 'Bạn có thẻ tích điểm không?'),
  ('00000000-0000-0000-0009-000000000005', 'en', 6, 'user', 'Yes, I have a T-Point card. Here you go.', 'Có, tôi có thẻ T-Point. Đây ạ.'),
  ('00000000-0000-0000-0009-000000000005', 'en', 7, 'partner', 'Thank you. Your total comes to eight hundred and twenty yen.', 'Cảm ơn. Tổng cộng là 820 yên.'),
  ('00000000-0000-0000-0009-000000000005', 'en', 8, 'user', 'I''ll pay by IC card — is that okay?', 'Tôi sẽ thanh toán bằng thẻ IC — được không?'),
  ('00000000-0000-0000-0009-000000000005', 'en', 9, 'partner', 'Of course. Please hold it over the reader.', 'Tất nhiên. Xin đặt thẻ lên đầu đọc.'),
  ('00000000-0000-0000-0009-000000000005', 'en', 10, 'user', 'Do I need a bag for this?', 'Tôi có cần túi không?'),
  ('00000000-0000-0000-0009-000000000005', 'en', 11, 'partner', 'Plastic bags are three yen. Would you like one?', 'Túi nhựa là 3 yên. Bạn có muốn không?'),
  ('00000000-0000-0000-0009-000000000005', 'en', 12, 'user', 'Yes please — just one. Thank you for heating the bento too.', 'Có ạ — một cái thôi. Cảm ơn bạn đã hâm nóng hộp cơm.');
INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation, furigana, romaji) VALUES
  ('00000000-0000-0000-0009-000000000006', 'ja', 1, 'partner', 'いらっしゃいませ！', 'Chào mừng quý khách!', 'いらっしゃいませ！', 'Irasshaimase!'),
  ('00000000-0000-0000-0009-000000000006', 'ja', 2, 'user', 'すみません、これを温めてもらえますか？[お弁当を差し出す]', 'Xin lỗi, bạn có thể hâm nóng cái này không? [đưa hộp cơm bento]', 'すみません、これをあたためてもらえますか？', 'Sumimasen, kore wo atatamete moraemasu ka?'),
  ('00000000-0000-0000-0009-000000000006', 'ja', 3, 'partner', 'はい、かしこまりました。以上でよろしいですか？', 'Vâng, được ạ. Bạn còn muốn gì thêm không?', 'はい、かしこまりました。いじょうでよろしいですか？', 'Hai, kashikomarimashita. Ijō de yoroshii desu ka?'),
  ('00000000-0000-0000-0009-000000000006', 'ja', 4, 'user', 'このコーヒーとサンドイッチも一緒にお願いします。', 'Cái cà phê này và bánh mì sandwich cũng cùng nhé.', 'このコーヒーとサンドイッチもいっしょにおねがいします。', 'Kono kōhī to sandoicchi mo issho ni onegai shimasu.'),
  ('00000000-0000-0000-0009-000000000006', 'ja', 5, 'partner', 'ポイントカードはお持ちですか？', 'Bạn có thẻ tích điểm không?', 'ポイントカードはおもちですか？', 'Pointo kādo wa o-mochi desu ka?'),
  ('00000000-0000-0000-0009-000000000006', 'ja', 6, 'user', 'はい、Tポイントカードを持っています。どうぞ。', 'Có, tôi có thẻ T-Point. Đây ạ.', 'はい、Tポイントカードをもっています。どうぞ。', 'Hai, T-pointo kādo wo motte imasu. Dōzo.'),
  ('00000000-0000-0000-0009-000000000006', 'ja', 7, 'partner', 'ありがとうございます。お会計は820円になります。', 'Cảm ơn. Tổng cộng là 820 yên.', 'ありがとうございます。おかいけいははっぴゃくにじゅうえんになります。', 'Arigatō gozaimasu. O-kaikei wa happyaku nijū en ni narimasu.'),
  ('00000000-0000-0000-0009-000000000006', 'ja', 8, 'user', 'ICカードで払えますか？', 'Tôi có thể thanh toán bằng thẻ IC không?', 'ICカードではらえますか？', 'Aishipi kādo de haraemasu ka?'),
  ('00000000-0000-0000-0009-000000000006', 'ja', 9, 'partner', 'はい、こちらのリーダーにタッチしてください。', 'Được, xin đặt thẻ lên đầu đọc này.', 'はい、こちらのリーダーにタッチしてください。', 'Hai, kochira no rīdā ni tatchi shite kudasai.'),
  ('00000000-0000-0000-0009-000000000006', 'ja', 10, 'user', '袋はもらえますか？', 'Tôi có thể lấy túi không?', 'ふくろはもらえますか？', 'Fukuro wa moraemasu ka?'),
  ('00000000-0000-0000-0009-000000000006', 'ja', 11, 'partner', 'レジ袋は3円になりますが、いかがでしょうか？', 'Túi nhựa là 3 yên, bạn có muốn không?', 'レジぶくろはさんえんになりますが、いかがでしょうか？', 'Reji-bukuro wa san-en ni narimasu ga, ikaga deshō ka?'),
  ('00000000-0000-0000-0009-000000000006', 'ja', 12, 'user', 'はい、一枚ください。お弁当も温めていただいてありがとうございます。', 'Có, cho tôi một cái. Cảm ơn đã hâm nóng hộp cơm.', 'はい、いちまいください。おべんとうもあたためていただいてありがとうございます。', 'Hai, ichi-mai kudasai. O-bentō mo atatamete itadaite arigatō gozaimasu.');
INSERT INTO scenario_groups (id, slug, category) VALUES
  ('00000000-0000-0000-0000-000000000022', 'japan-specific4', 'culture')
INSERT INTO scenarios (id, group_id, language_id, title, description, level, type, icon, sort_order) VALUES
  (
INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation) VALUES
  ('00000000-0000-0000-0009-000000000007', 'en', 1, 'user', 'Excuse me — is this my first time at an onsen, and I''m not sure about the rules. Could you help me?', 'Xin lỗi — đây là lần đầu tôi đến onsen và tôi không chắc về quy tắc. Bạn có thể giúp tôi không?'),
  ('00000000-0000-0000-0009-000000000007', 'en', 2, 'partner', 'Of course! First, please wash your body thoroughly at the washing stations before entering the bath.', 'Tất nhiên! Trước tiên, hãy rửa sạch người tại các trạm tắm trước khi vào bồn.'),
  ('00000000-0000-0000-0009-000000000007', 'en', 3, 'user', 'Do I need to bring my own towel, or is one provided?', 'Tôi có cần mang khăn riêng không, hay có cung cấp sẵn?'),
  ('00000000-0000-0000-0009-000000000007', 'en', 4, 'partner', 'We provide a small towel. Please don''t take it into the bath — just leave it at the side or on your head.', 'Chúng tôi cung cấp khăn nhỏ. Xin đừng mang vào bồn — hãy để bên ngoài hoặc đặt trên đầu.'),
  ('00000000-0000-0000-0009-000000000007', 'en', 5, 'user', 'Got it. Is it alright if I have a tattoo?', 'Hiểu rồi. Nếu tôi có xăm hình thì sao?'),
  ('00000000-0000-0000-0009-000000000007', 'en', 6, 'partner', 'I''m sorry, our facility doesn''t allow tattoos in the shared baths. We do have a private bath available if you''d like.', 'Xin lỗi, cơ sở của chúng tôi không cho phép xăm trong bồn tắm chung. Nhưng chúng tôi có bồn riêng nếu bạn muốn.'),
  ('00000000-0000-0000-0009-000000000007', 'en', 7, 'user', 'I see. How long is it usually recommended to stay in the water?', 'Tôi hiểu. Thông thường nên ngâm trong bao lâu?'),
  ('00000000-0000-0000-0009-000000000007', 'en', 8, 'partner', 'Around ten to fifteen minutes, then take a break, hydrate, and you can go back in. Drink plenty of water.', 'Khoảng 10-15 phút, rồi nghỉ, uống nước, và có thể vào lại. Hãy uống nhiều nước.'),
  ('00000000-0000-0000-0009-000000000007', 'en', 9, 'user', 'Is it okay to talk quietly inside?', 'Có thể nói chuyện nhỏ bên trong không?'),
  ('00000000-0000-0000-0009-000000000007', 'en', 10, 'partner', 'Soft conversation is fine, but please keep voices low. Many guests come here to relax in quiet.', 'Nói chuyện nhẹ nhàng thì được, nhưng xin giữ giọng nhỏ. Nhiều khách đến đây để thư giãn trong yên tĩnh.'),
  ('00000000-0000-0000-0009-000000000007', 'en', 11, 'user', 'Of course. And no phones or cameras, I assume?', 'Tất nhiên. Và không điện thoại hay máy ảnh, tôi đoán vậy?'),
  ('00000000-0000-0000-0009-000000000007', 'en', 12, 'partner', 'Exactly — no devices in the bathing area, please. Enjoy your visit, and please let us know if you need anything.', 'Đúng vậy — không thiết bị trong khu vực tắm. Chúc bạn thư giãn vui vẻ, và hãy cho chúng tôi biết nếu cần gì.');
INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation, furigana, romaji) VALUES
  ('00000000-0000-0000-0009-000000000008', 'ja', 1, 'user', 'すみません、温泉は初めてなのですが、マナーがよくわからなくて。教えていただけますか？', 'Xin lỗi, đây là lần đầu tôi đến onsen và tôi không biết nhiều về quy tắc. Bạn có thể chỉ dạy không?', 'すみません、おんせんははじめてなのですが、マナーがよくわからなくて。おしえていただけますか？', 'Sumimasen, onsen wa hajimete na no desu ga, manā ga yoku wakaranakute. Oshiete itadakemasu ka?'),
  ('00000000-0000-0000-0009-000000000008', 'ja', 2, 'partner', 'もちろんです。まず、浴槽に入る前に洗い場で体をきれいに洗ってください。', 'Tất nhiên. Trước tiên, hãy rửa sạch người tại khu vực tắm trước khi vào bồn.', 'もちろんです。まず、よくそうにはいるまえにあらいばでからだをきれいにあらってください。', 'Mochiron desu. Mazu, yokusō ni hairu mae ni araiba de karada wo kirei ni aratte kudasai.'),
  ('00000000-0000-0000-0009-000000000008', 'ja', 3, 'user', 'タオルは持参が必要ですか、それとも貸していただけますか？', 'Tôi cần mang khăn riêng không, hay có cho mượn?', 'タオルはじさんがひつようですか、それともかしていただけますか？', 'Taoru wa jisan ga hitsuyō desu ka, soretomo kashite itadakemasu ka?'),
  ('00000000-0000-0000-0009-000000000008', 'ja', 4, 'partner', '小さなタオルをご用意しています。浴槽には入れないでください。洗い場の隅に置くか、頭の上に乗せてください。', 'Chúng tôi có cung cấp khăn nhỏ. Xin đừng mang vào bồn. Để ở góc khu tắm hoặc đặt trên đầu.', 'ちいさなタオルをごよういしています。よくそうにはいれないでください。あらいばのすみにおくか、あたまのうえにのせてください。', 'Chiisana taoru wo go-yōi shite imasu. Yokusō ni wa irenaide kudasai. Araiba no sumi ni oku ka, atama no ue ni nosete kudasai.'),
  ('00000000-0000-0000-0009-000000000008', 'ja', 5, 'user', 'タトゥーがあるのですが、大丈夫でしょうか？', 'Tôi có xăm hình, có sao không?', 'タトゥーがあるのですが、だいじょうぶでしょうか？', 'Tatū ga aru no desu ga, daijōbu deshō ka?'),
  ('00000000-0000-0000-0009-000000000008', 'ja', 6, 'partner', '申し訳ございませんが、共用浴槽ではタトゥーのある方のご利用をご遠慮いただいています。貸し切り風呂はご利用いただけます。', 'Xin lỗi, chúng tôi yêu cầu khách có xăm hình không sử dụng bồn chung. Bạn có thể sử dụng phòng tắm riêng.', 'もうしわけございませんが、きょうようよくそうではタトゥーのあるかたのごりようをごえんりょいただいています。かしきりぶろはごりようできます。', 'Mōshiwake gozaimasen ga, kyōyō yokusō de wa tatū no aru kata no go-riyō wo go-enryo itadaite imasu. Kashikiri buro wa go-riyō itadakemasu.'),
  ('00000000-0000-0000-0009-000000000008', 'ja', 7, 'user', 'わかりました。どのくらい入浴するのがいいですか？', 'Hiểu rồi. Nên ngâm bao lâu là tốt?', 'わかりました。どのくらいにゅうよくするのがいいですか？', 'Wakarimashita. Dono kurai nyūyoku suru no ga ii desu ka?'),
  ('00000000-0000-0000-0009-000000000008', 'ja', 8, 'partner', '10〜15分を目安に、その後は休憩して水分補給をしてください。そしてまた入っていただけます。水をたくさん飲んでください。', 'Khoảng 10–15 phút, sau đó nghỉ và bổ sung nước. Rồi có thể vào lại. Hãy uống nhiều nước.', 'じゅっからじゅうごふんをめやすに、そのごはきゅうけいしてすいぶんほきゅうをしてください。そしてまたはいっていただけます。みずをたくさんのんでください。', 'Jū kara jūgo-fun wo meyasu ni, sono go wa kyūkei shite suibun hokyū wo shite kudasai. Soshite mata haitte itadakemasu. Mizu wo takusan nonde kudasai.'),
  ('00000000-0000-0000-0009-000000000008', 'ja', 9, 'user', '中で静かに話してもいいですか？', 'Có thể nói chuyện nhỏ bên trong không?', 'なかでしずかにはなしてもいいですか？', 'Naka de shizuka ni hanashite mo ii desu ka?'),
  ('00000000-0000-0000-0009-000000000008', 'ja', 10, 'partner', '小さな声でのご会話はかまいません。ただ、静かにお過ごしになりたいお客様もいらっしゃいますので、お声はお控えください。', 'Nói nhỏ thì được. Nhưng nhiều khách muốn nghỉ ngơi trong yên tĩnh, xin hạ giọng.', 'ちいさなこえでのごかいわはかまいません。ただ、しずかにおすごしになりたいおきゃくさまもいらっしゃいますので、おこえはおひかえください。', 'Chiisana koe de no go-kaiwa wa kamaimasen. Tada, shizuka ni o-sugoshi ni naritai o-kyaku-sama mo irasshaimasu node, o-koe wa o-hikae kudasai.'),
  ('00000000-0000-0000-0009-000000000008', 'ja', 11, 'user', 'もちろんです。浴場内では携帯電話やカメラは使えませんよね？', 'Tất nhiên. Trong khu tắm không dùng điện thoại hay máy ảnh đúng không?', 'もちろんです。よくじょうないではけいたいでんわやカメラはつかえませんよね？', 'Mochiron desu. Yokujō nai de wa keitai denwa ya kamera wa tsukaemasen yo ne?'),
  ('00000000-0000-0000-0009-000000000008', 'ja', 12, 'partner', 'おっしゃる通りです。浴場内での機器のご使用はお断りしております。ごゆっくりお楽しみください。ご不明な点があればいつでもお申し付けください。', 'Đúng vậy. Chúng tôi không cho phép sử dụng thiết bị trong khu tắm. Chúc bạn thư giãn vui vẻ. Có gì cần hãy hỏi chúng tôi.', 'おっしゃるとおりです。よくじょうないでのききのごしようはおことわりしております。ごゆっくりおたのしみください。ごふめいなてんがあればいつでもおもうしつけください。', 'Ossharu tōri desu. Yokujō nai de no kiki no go-shiyō wa o-kotowari shite orimasu. Go-yukkuri o-tanoshimi kudasai. Go-fumei na ten ga areba itsu de mo o-mōshitsuke kudasai.');
